"""Implementation of the valkey client (valkey-py_)."""

import os
try:
    import pwd  # Unix only
except ImportError:
    pwd = None
import logging
import warnings

import valkey
from searx import get_setting

_CLIENT: valkey.Valkey | None = None
logger = logging.getLogger(__name__)


def _windows_safe_current_user():
    if pwd is not None and hasattr(os, "getuid"):
        try:
            _pw = pwd.getpwuid(os.getuid())
            return _pw.pw_name, _pw.pw_uid
        except Exception:
            pass

    username = (
        os.environ.get("USERNAME")
        or os.environ.get("USER")
        or os.environ.get("LOGNAME")
        or "windows"
    )
    return username, -1



def client() -> valkey.Valkey | None:
    return _CLIENT


def initialize():
    global _CLIENT
    if get_setting('redis.url'):
        warnings.warn("setting redis.url is deprecated, use valkey.url", DeprecationWarning)
    valkey_url = get_setting('valkey.url') or get_setting('redis.url')
    if not valkey_url:
        return False
    try:
        _CLIENT = valkey.Valkey.from_url(valkey_url)
        _CLIENT.ping()
        logger.info("connected to Valkey")
        return True
    except valkey.exceptions.ValkeyError:
        _CLIENT = None
        _user_name, _user_uid = _windows_safe_current_user()
        logger.exception("[%s (%s)] can't connect valkey DB ...", _user_name, _user_uid)
    return False
